// CLX Copilot Platform Q&A v1 — Validate + intent detection
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const token = body.token || null;
const question = body.question || '';
let intent = body.intent || null;

const masterToken = process.env.MARY_MASTER_TOKEN || 'TODO_SET_MARY_MASTER_TOKEN';
if (!token || masterToken === 'TODO_SET_MARY_MASTER_TOKEN' || token !== masterToken) {
  return { json: { _unauthorized: true, error: 'admin token required' } };
}
if (!question) {
  return { json: { _empty: true, error: 'question required' } };
}

// Light-weight intent detection if not provided
if (!intent) {
  const q = question.toLowerCase();
  if (q.match(/how many|count of|total|sum|average|list/)) intent = 'database_content';
  else if (q.match(/roadmap|planned|future|when will|upcoming/)) intent = 'roadmap';
  else if (q.match(/feature|capability|what can|what does/)) intent = 'current_features';
  else if (q.match(/workflow|n8n|active|status of/)) intent = 'workflow_status';
  else if (q.match(/improve|idea|suggest|should we|could we/)) intent = 'improvement_ideas';
  else intent = 'current_features';
}

return { json: { token, question, intent, _authorized: true } };

// CLX Copilot Platform Q&A v1 — Gather context
// Context varies by intent:
//   current_features -> reads OPERATIONS_HANDBOOK.md (conceptual)
//   database_content -> reads information_schema (deferred to
//     admin_execute_select on a follow-up call)
//   roadmap          -> reads ROADMAP_*.md (list references)
//   workflow_status  -> reads workflow JSON files (list references)
//
// In this scaffold, we pass the intent to Claude and reference the
// source files by path; Claude is responsible for saying "check
// docs/architecture/OPERATIONS_HANDBOOK.md section X" rather than
// inventing content. A future enhancement will actually fetch the
// file contents and pass as context.

const input = $input.item.json;

const sourceHints = {
  current_features: [
    'docs/architecture/OPERATIONS_HANDBOOK.md — primary source for features',
    'docs/verticals/*/README.md — per-vertical capability catalog',
    'docs/commercial/LANDING_PAGE_COPY.md — customer-facing feature summary'
  ],
  database_content: [
    'docs/architecture/migrations/2026-04-*.sql — schema definitions',
    'docs/dashboard/AUDIT.md — current query patterns',
    'For specific counts or rows, use the DB Query copilot instead'
  ],
  roadmap: [
    'docs/architecture/ROADMAP_B9_MARKET_INTELLIGENCE.md',
    'docs/architecture/FUTURE_BEAUTY_MARKETPLACE_ROADMAP.md',
    'docs/architecture/QUEUED_VERTICAL_SEEDING_B2B.md',
    'docs/architecture/VERTICAL_EXPANSION_RANKING.md'
  ],
  workflow_status: [
    'workflows/*.json — 26+ n8n workflows',
    'Only clx-lead-import is active=true at current state',
    'All others are scaffolded active=false with activation steps in OPERATIONS_HANDBOOK'
  ],
  improvement_ideas: [
    'Reference existing roadmaps before proposing new; many ideas are already captured',
    'See VERTICAL_EXPANSION_RANKING.md for vertical strategy',
    'See ROADMAP_B9_MARKET_INTELLIGENCE.md for market-intel tier'
  ]
};

const hints = sourceHints[input.intent] || sourceHints.current_features;

return { json: {
  question: input.question,
  intent: input.intent,
  hints: hints,
  systemContext: 'You are Crystallux Platform Q&A Copilot. Ground your answers in the files listed in the source_hints below. When you do not know, say so. Reference existing roadmaps before proposing new ideas. Mary has already shipped a lot — check what exists before suggesting net-new work.'
} };

// CLX Copilot Platform Q&A v1 — Parse Claude + build response
const resp = $input.item.json || {};
const input = $('Validate + Detect Intent').first().json;

let payload = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  payload = JSON.parse(text.trim());
} catch (e) {
  return { json: { ok: false, error: 'Claude response was not valid JSON', raw: (resp.content && resp.content[0] && resp.content[0].text) || null } };
}

return { json: {
  ok: true,
  answer: payload.answer || '',
  sources: Array.isArray(payload.sources) ? payload.sources : [],
  intent: input.intent,
  question: input.question
} };
